// ============================================================
// generateBA.js — Isi template BA Penyelesaian Pekerjaan docx di browser
// Template di-embed sebagai base64, hanya placeholder 'xxx' dan
// data penandatangan (jika disediakan) yang diganti. Format dipertahankan.
// ============================================================

import JSZip from 'jszip';

const TEMPLATES = {
  PANITIA:  '',
  PULDADIS: '',
};

const BULAN = ['','Januari','Februari','Maret','April','Mei','Juni',
  'Juli','Agustus','September','Oktober','November','Desember'];
const HARI_MAP = {0:'Minggu',1:'Senin',2:'Selasa',3:'Rabu',4:'Kamis',5:'Jumat',6:'Sabtu'};

// "Senin, 4 Mei" (tahun sudah tercetak di template setelah placeholder)
function hariTanggal(iso) {
  if (!iso) return '___';
  const p = String(iso).substring(0, 10).split('-');
  if (p.length !== 3) return String(iso);
  const d = new Date(iso + 'T00:00:00');
  const hari = isNaN(d) ? '' : (HARI_MAP[d.getDay()] || '');
  const tgl = parseInt(p[2], 10);
  const bln = BULAN[parseInt(p[1], 10)] || '';
  return `${hari ? hari + ', ' : ''}${tgl} ${bln}`.trim();
}

function xe(s) {
  return String(s == null ? '' : s)
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

/**
 * Generate dan unduh BA Penyelesaian Pekerjaan.
 * Hanya placeholder 'xxx' yang diisi; sisa template (kop, penandatangan,
 * footer Freestyle Script, font) dipertahankan apa adanya.
 * @param {Object} baResult
 *   - jenis: 'PANITIA' | 'PULDADIS'
 *   - No_BA / nomor: nomor BA          -> "NOMOR : xxx"
 *   - Tanggal_BA (ISO) / tanggal       -> "Pada Hari ini, [hari, tgl bulan] 2026"
 *   - jumlahBidang                     -> "sejumlah xxx bidang"
 */
export async function generateAndDownloadBA(baResult = {}) {
  const jenisRaw = String(baResult.jenis || baResult.Kode_Jenis_BA || 'PULDADIS').toUpperCase();
  const jenis = TEMPLATES[jenisRaw] ? jenisRaw : 'PULDADIS';

  const nomor = String(baResult.No_BA || baResult.nomor || '___');
  const tglBA = String(baResult.Tanggal_BA || baResult.tanggal || '');
  const jmlBidang = baResult.jumlahBidang != null && String(baResult.jumlahBidang).trim() !== ''
    ? String(baResult.jumlahBidang) : '___';
  const hariStr = tglBA ? hariTanggal(tglBA) : '___';

  // Load template
  const b64 = TEMPLATES[jenis];
  const bin = atob(b64);
  const arr = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
  const zip = await JSZip.loadAsync(arr.buffer);
  let xml = await zip.file('word/document.xml').async('string');

  // Placeholder 'xxx' (\u2018xxx\u2019)
  // 1. Jumlah bidang lebih spesifik: "sejumlah xxx bidang"
  xml = xml.replace(/(sejumlah\s*)\u2018xxx\u2019(\s*bidang)/g,
    (m, a, b) => `${a}${xe(jmlBidang)}${b}`);

  // 2. Sisa dua placeholder dalam urutan dokumen: (1) NOMOR, (2) Pada Hari ini.
  //    Ganti hanya token-nya, spasi/markup run di sekitarnya dipertahankan.
  let k = 0;
  xml = xml.replace(/\u2018xxx\u2019/g, () => {
    k++;
    if (k === 1) return xe(nomor);
    if (k === 2) return xe(hariStr);
    return '\u2018xxx\u2019';
  });

  zip.file('word/document.xml', xml);
  const outBin = await zip.generateAsync({ type: 'uint8array', compression: 'DEFLATE' });
  const blob = new Blob([outBin], {
    type: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  });

  const safeNomor = nomor.replace(/[\/\\:*?"<>|]/g, '-');
  const filename = `BA_${jenis}_${safeNomor}.docx`;
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);

  return { filename, jenis, nomor };
}
